import React, { useState, useMemo, useCallback, useRef, useEffect, startTransition, useDeferredValue } from "react";

// ─── ENGINE ─────────────────────────────────────────────────────────────────
const _reCache=new Map();
function mw(p,o){if(p===o)return!0;if(p==="*")return!0;if(p==="*/read")return o.endsWith("/read");let re=_reCache.get(p);if(!re){re=new RegExp("^"+p.replace(/[.+?^${}()|[\]\\]/g,"\\$&").replace(/\\\./g,"\\.").replace(/\*/g,".*")+"$","i");_reCache.set(p,re)}return re.test(o)}
function rc(r,op){const pool=op.type==="dataAction"?(r.dataActions||[]):(r.actions||[]),not=op.type==="dataAction"?(r.notDataActions||[]):(r.notActions||[]);return pool.some(p=>mw(p,op.action))&&!not.some(p=>mw(p,op.action))}
function findRoles(roles,ops){if(!ops.length)return[];const total=ops.length,minC=Math.ceil(total*0.6);return roles.map(r=>{const ha=(r.actions||[]).some(a=>a.includes("*")),hd=(r.dataActions||[]).some(a=>a.includes("*"));if(!ha&&!hd){const maxP=(r.actions||[]).length+(r.dataActions||[]).length;if(maxP<minC)return null}let covered=0;const missed=[];for(const o of ops){if(rc(r,o))covered++;else missed.push(o)}if(covered<minC)return null;return{...r,coveredCount:covered,missedOps:missed,missedCount:missed.length,coverage:covered/total,est:r._estimatedActions||1}}).filter(Boolean).sort((a,b)=>b.coverage!==a.coverage?b.coverage-a.coverage:a.est-b.est).slice(0,10)}
function mkJSON(ops){return JSON.stringify({properties:{roleName:"Custom Least Privilege Role",description:"Generated by Least Privilege Studio for Azure",assignableScopes:["/subscriptions/<subscription-id>","/subscriptions/<subscription-id>/resourceGroups/<resource-group>","/providers/Microsoft.Management/managementGroups/<management-group-id>"],permissions:[{actions:ops.filter(o=>o.type==="action").map(o=>o.action),notActions:[],dataActions:ops.filter(o=>o.type==="dataAction").map(o=>o.action),notDataActions:[]}]}},null,2)}

// ─── SEARCH SYNONYMS ────────────────────────────────────────────────────────
const ABBREV={"vm":"virtual machines","nic":"network interfaces nics","nsg":"network security groups nsgs","vnet":"virtual networks","aks":"aks clusters managedclusters kubernetes","acr":"container registries","avd":"avd host pools virtual desktop","rg":"resource groups","lb":"load balancers","dns":"dns zones","kv":"key vaults keyvault","pip":"public ip addresses","k8s":"kubernetes aks","sql":"sql servers databases"};

// Returns { filtered: categories, isPermSearch: bool, permQuery: string }
function searchMatch(query,categories){
  if(!query.trim())return{filtered:categories,isPermSearch:false,permQuery:""};
  const q=query.toLowerCase().trim();
  // Mode 1: explicit permission path (contains / or microsoft.)
  if(q.includes("/")||q.includes("microsoft.")){
    const f=categories.map(cat=>({...cat,providers:cat.providers.map(p=>({...p,types:p.types.filter(t=>t.actions.some(a=>a.ops.some(o=>o.action.toLowerCase().includes(q))))})).filter(p=>p.types.length>0)})).filter(c=>c.providers.length>0);
    return{filtered:f,isPermSearch:true,permQuery:q};
  }
  // Mode 2: word-boundary match on names + substring match on operation paths
  const words=q.split(/\s+/).filter(Boolean);
  const f=categories.map(cat=>({...cat,providers:cat.providers.map(p=>({...p,types:p.types.filter(t=>{
    // Build name haystack
    const nameHay=(t.name+" "+t.key+" "+p.displayName+" "+cat.name).toLowerCase();
    let expandedHay=nameHay;
    for(const w of words){if(ABBREV[w])expandedHay+=" "+ABBREV[w]}
    // Check 1: ALL words match in the name context (word-boundary)
    const allMatchName=words.every(w=>{
      const wb=new RegExp("\\b"+w.replace(/[.*+?^${}()|[\]\\]/g,"\\$&"),"i");
      if(wb.test(expandedHay))return true;
      if(ABBREV[w])return ABBREV[w].split(/\s+/).some(sw=>new RegExp("\\b"+sw.replace(/[.*+?^${}()|[\]\\]/g,"\\$&"),"i").test(nameHay));
      return false;
    });
    if(allMatchName)return true;
    // Check 2: ALL words match as substrings within at least one operation path
    const allOps=t.actions.flatMap(a=>a.ops.map(o=>o.action.toLowerCase()));
    const allMatchOps=allOps.some(op=>words.every(w=>op.includes(w)));
    return allMatchOps;
  })})).filter(p=>p.types.length>0)})).filter(c=>c.providers.length>0);
  return{filtered:f,isPermSearch:false,permQuery:""};
}

// Highlight matching text in a string
function HL({text,query}){
  if(!query||query.length<2)return text;
  const words=query.toLowerCase().split(/\s+/).filter(w=>w.length>=2);
  // Also add abbreviation expansions
  const allWords=[...words];
  for(const w of words)if(ABBREV[w])allWords.push(...ABBREV[w].split(/\s+/).filter(s=>s.length>=2));
  if(!allWords.length)return text;
  const pat=allWords.map(w=>w.replace(/[.*+?^${}()|[\]\\]/g,"\\$&")).join("|");
  const re=new RegExp(`(${pat})`,"gi");
  const parts=text.split(re);
  return parts.map((p,i)=>re.test(p)?<span key={i} style={{color:"#4fc3f7",fontWeight:700}}>{p}</span>:p);
}

