const FN={"virtualMachines":"Virtual Machines","virtualMachines/extensions":"VM Extensions","virtualMachineScaleSets":"VM Scale Sets","disks":"Managed Disks","snapshots":"Disk Snapshots","galleries":"Compute Galleries","galleries/images/versions":"Gallery Image Versions","availabilitySets":"Availability Sets","virtualNetworks":"Virtual Networks","virtualNetworks/subnets":"Subnets","networkInterfaces":"Network Interfaces (NICs)","publicIPAddresses":"Public IP Addresses","networkSecurityGroups":"Network Security Groups (NSGs)","loadBalancers":"Load Balancers","applicationGateways":"Application Gateways","routeTables":"Route Tables","privateDnsZones":"Private DNS Zones","privateEndpoints":"Private Endpoints","bastionHosts":"Bastion Hosts","natGateways":"NAT Gateways","azureFirewalls":"Azure Firewalls","virtualNetworkGateways":"VPN Gateways","storageAccounts":"Storage Accounts","storageAccounts/blobServices/containers":"Blob Containers","storageAccounts/blobServices/containers/blobs":"Blobs (Data Plane)","storageAccounts/fileServices/fileshares":"File Shares","storageAccounts/queueServices/queues":"Queues","storageAccounts/tableServices/tables":"Tables","servers":"Servers","servers/databases":"Databases","servers/elasticPools":"Elastic Pools","flexibleServers":"Flexible Servers","databaseAccounts":"Cosmos DB Accounts","sites":"Web Apps / Function Apps","serverfarms":"App Service Plans","staticSites":"Static Web Apps","managedClusters":"AKS Clusters","registries":"Container Registries","containerGroups":"Container Instances","vaults":"Key Vaults","vaults/secrets":"Secrets","vaults/keys":"Keys","vaults/certificates":"Certificates","hostpools":"Host Pools","hostpools/sessionhosts":"Session Hosts","applicationgroups":"Application Groups","roleAssignments":"Role Assignments","roleDefinitions":"Role Definitions","policyAssignments":"Policy Assignments","policyDefinitions":"Policy Definitions","subscriptions/resourceGroups":"Resource Groups","deployments":"Deployments","userAssignedIdentities":"Managed Identities","workspaces":"Workspaces","components":"Application Insights"};
const PN={"Microsoft.Compute":"Compute","Microsoft.Network":"Network","Microsoft.Storage":"Storage","Microsoft.ClassicStorage":"Classic Storage","Microsoft.NetApp":"NetApp Files","Microsoft.Sql":"SQL","Microsoft.DBforMySQL":"MySQL","Microsoft.DBforPostgreSQL":"PostgreSQL","Microsoft.DocumentDB":"Cosmos DB","Microsoft.Cache":"Redis Cache","Microsoft.DataFactory":"Data Factory","Microsoft.Kusto":"Data Explorer","Microsoft.Web":"App Service","Microsoft.App":"Container Apps","Microsoft.ApiManagement":"API Management","Microsoft.ContainerService":"AKS","Microsoft.ContainerRegistry":"Container Registry","Microsoft.ContainerInstance":"Container Instances","Microsoft.MachineLearningServices":"Machine Learning","Microsoft.CognitiveServices":"Cognitive Services / OpenAI","Microsoft.Search":"AI Search","Microsoft.KeyVault":"Key Vault","Microsoft.Security":"Security Center","Microsoft.SecurityInsights":"Sentinel","Microsoft.ManagedIdentity":"Managed Identity","Microsoft.Insights":"Monitor / Insights","Microsoft.OperationalInsights":"Log Analytics","Microsoft.Authorization":"Authorization","Microsoft.Resources":"Resource Manager","Microsoft.CostManagement":"Cost Management","Microsoft.Support":"Support","Microsoft.Logic":"Logic Apps","Microsoft.EventHub":"Event Hubs","Microsoft.EventGrid":"Event Grid","Microsoft.ServiceBus":"Service Bus","Microsoft.Devices":"IoT Hub","Microsoft.Databricks":"Databricks","Microsoft.Synapse":"Synapse Analytics","Microsoft.DesktopVirtualization":"Virtual Desktop","Microsoft.RecoveryServices":"Recovery Services","Microsoft.DevTestLab":"DevTest Labs","Microsoft.Migrate":"Migrate"};
function fn(k){return FN[k]||k.split("/").pop().replace(/([a-z])([A-Z])/g,"$1 $2").replace(/([A-Z]+)([A-Z][a-z])/g,"$1 $2").replace(/^./,s=>s.toUpperCase()).trim()}
function pn(ns){return PN[ns]||ns.replace("Microsoft.","")}

// Classify an operation into access level
function accessLevel(opAction){
  const last=opAction.split("/").pop().toLowerCase();
  const prev=opAction.split("/").slice(-2,-1)[0]?.toLowerCase()||"";
  if(last==="read")return"Read";
  if(last==="write")return"Write";
  if(last==="delete")return"Delete";
  if(last==="action"){
    if(["join","start","stop","deallocate","poweroff","restart","reboot","listkeys","regeneratekey","failover","backup","restore"].includes(prev))return"Action";
    return"Action";
  }
  return"Action";
}

// Short display name for an operation (just the meaningful part)
function opShortName(action, ns){
  const rest=action.slice(ns.length+1);
  return rest;
}

